// O(1) - Constant: input kitna bhi bada ho, same speed
public int getFirst(int[] arr) {
    return arr[0];  // 10 lakh items ho ya 10, same time lagega
}

// O(n) - Linear: input ke saath badhta hai
public int findMax(int[] arr) {
    int max = arr[0];
    for (int num : arr) {  // Har element ko ek baar touch karo
        if (num > max) max = num;
    }
    return max;
}

// O(log n) - Logarithmic: problem ko aadha aadha karta hai
public int binarySearch(int[] arr, int target) {
    int left = 0, right = arr.length - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;  // Aadha kar do
        if (arr[mid] == target) return mid;
        if (arr[mid] < target) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}

// O(n²) - Quadratic: nested loops = bade input pe musibat
public void bubbleSort(int[] arr) {
    for (int i = 0; i < arr.length; i++) {       // n baar
        for (int j = 0; j < arr.length - 1; j++) { // har baar n kaam
            // Total: n * n = n² operations!
            if (arr[j] > arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

// O(1) Space - Bas kuch variables, input kitna bhi bada ho
public void reverseArray(int[] arr) {
    int left = 0, right = arr.length - 1;  // Sirf 3 variables!
    while (left < right) {
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;
        right--;
    }
}

// O(n) Space - Copy banane mein input jitni jagah chahiye
public int[] copyArray(int[] arr) {
    int[] copy = new int[arr.length];  // Naya array = O(n) space
    for (int i = 0; i < arr.length; i++) {
        copy[i] = arr[i];
    }
    return copy;
}

// O(n) Space - Recursion stack memory khata hai!
public int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);  // Har call stack mein jaati hai
    // factorial(5) → factorial(4) → ... → factorial(1)
    // 5 function calls ek saath memory mein baithe hain!
}

