// Array ulta karo in-place — classic two-pointer swap
public void reverse(int[] arr) {
    int left = 0, right = arr.length - 1;
    while (left < right) {
        // Left aur right wali gaadi swap karo
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;    // Center ki taraf badho
        right--;   // Center ki taraf badho
    }
}

// SORTED array pe Two Sum — classic two-pointer example
public int[] twoSum(int[] arr, int target) {
    int left = 0, right = arr.length - 1;

    while (left < right) {
        int sum = arr[left] + arr[right];

        if (sum == target) {
            return new int[]{left, right};  // Mil gaya!
        } else if (sum < target) {
            left++;   // Bada sum chahiye → left aage badho
        } else {
            right--;  // Chhota sum chahiye → right peeche aao
        }
    }
    return new int[]{-1, -1};  // Koi pair nahi mila
}

// Sorted Array se Duplicates Hatao
// Key insight: slow pointer mark karta hai unique ka position
public int removeDuplicates(int[] arr) {
    if (arr.length == 0) return 0;

    int slow = 0;  // Last unique element ki jagah

    for (int fast = 1; fast < arr.length; fast++) {
        if (arr[fast] != arr[slow]) {  // Naya unique mila!
            slow++;                     // Jagah banao
            arr[slow] = arr[fast];      // Rakh do
        }
    }
    return slow + 1;  // Unique elements ki count
}

// Size K ka Maximum Sum Subarray — classic fixed window
public int maxSumSubarray(int[] arr, int k) {
    // Pehle, pehli window ka sum nikalo
    int windowSum = 0;
    for (int i = 0; i < k; i++) {
        windowSum += arr[i];
    }
    int maxSum = windowSum;

    // Ab slide karo: left wala hatao, right wala jodo
    for (int i = k; i < arr.length; i++) {
        windowSum += arr[i] - arr[i - k];  // Slide!
        maxSum = Math.max(maxSum, windowSum);
    }
    return maxSum;
}

// Bina Repeating Characters ke Sabse Lamba Substring — variable window
public int lengthOfLongestSubstring(String s) {
    Set<Character> seen = new HashSet<>();
    int maxLen = 0, left = 0;

    for (int right = 0; right < s.length(); right++) {
        // Window tab tak chhoti karo jab tak duplicate na hat jaye
        while (seen.contains(s.charAt(right))) {
            seen.remove(s.charAt(left));
            left++;  // Left se shrink karo
        }

        seen.add(s.charAt(right));  // Window badhao
        maxLen = Math.max(maxLen, right - left + 1);
    }
    return maxLen;
}

// Maximum Subarray Sum - O(n)
public int maxSubArray(int[] nums) {
    int maxSum = nums[0];
    int currentSum = nums[0];

    for (int i = 1; i < nums.length; i++) {
        currentSum = Math.max(nums[i], currentSum + nums[i]);
        maxSum = Math.max(maxSum, currentSum);
    }
    return maxSum;
}

// Subarray indices bhi return karo
public int[] maxSubArrayWithIndices(int[] nums) {
    int maxSum = nums[0], currentSum = nums[0];
    int start = 0, end = 0, tempStart = 0;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] > currentSum + nums[i]) {
            currentSum = nums[i];
            tempStart = i;
        } else {
            currentSum = currentSum + nums[i];
        }

        if (currentSum > maxSum) {
            maxSum = currentSum;
            start = tempStart;
            end = i;
        }
    }
    return new int[]{start, end, maxSum};
}

// Sort Colors (0s, 1s, 2s) - O(n) time, O(1) space
public void sortColors(int[] nums) {
    int low = 0, mid = 0, high = nums.length - 1;

    while (mid <= high) {
        if (nums[mid] == 0) {
            swap(nums, low, mid);
            low++;
            mid++;
        } else if (nums[mid] == 1) {
            mid++;
        } else { // nums[mid] == 2
            swap(nums, mid, high);
            high--;
        }
    }
}

private void swap(int[] arr, int i, int j) {
    int temp = arr[i];
    arr[i] = arr[j];
    arr[j] = temp;
}

// Array ko k positions rotate karo - O(n) time, O(1) space
public void rotate(int[] arr, int k) {
    k = k % arr.length;
    reverse(arr, 0, arr.length - 1);
    reverse(arr, 0, k - 1);
    reverse(arr, k, arr.length - 1);
}

private void reverse(int[] arr, int start, int end) {
    while (start < end) {
        int temp = arr[start];
        arr[start] = arr[end];
        arr[end] = temp;
        start++;
        end--;
    }
}

// Missing Number dhundho (1 se n) - O(n)
public int findMissing(int[] arr) {
    int n = arr.length + 1;
    int expectedSum = n * (n + 1) / 2;
    int actualSum = 0;
    for (int num : arr) {
        actualSum += num;
    }
    return expectedSum - actualSum;
}

// Duplicate Number dhundho - O(n) time, O(1) space
public int findDuplicate(int[] nums) {
    int slow = nums[0];
    int fast = nums[0];

    do {
        slow = nums[slow];
        fast = nums[nums[fast]];
    } while (slow != fast);

    slow = nums[0];
    while (slow != fast) {
        slow = nums[slow];
        fast = nums[fast];
    }
    return slow;
}

