// Har node data + next node ka pointer rakhta hai
class Node {
    int data;
    Node next;  // Agle node ka 'pata'

    Node(int data) {
        this.data = data;
        this.next = null;
    }
}

public class LinkedList {
    Node head;  // List ka entry point

    // Shuru mein Insert - O(1) — sirf head update karo!
    public void insertAtBeginning(int data) {
        Node newNode = new Node(data);
        newNode.next = head;  // Naya node purane head ko point kare
        head = newNode;       // Naya node head ban gaya
    }

    // End mein Insert - O(n) — end tak walk karna padega
    public void insertAtEnd(int data) {
        Node newNode = new Node(data);
        if (head == null) { head = newNode; return; }

        Node current = head;
        while (current.next != null) {  // Last node tak jao
            current = current.next;
        }
        current.next = newNode;  // Last node ko naye node se jodo
    }
}

// Iterative Approach - O(n) time, O(1) space
public Node reverse() {
    Node prev = null;
    Node current = head;
    Node next = null;

    while (current != null) {
        next = current.next;  // Next save karo
        current.next = prev;  // Link ulta karo
        prev = current;       // prev aage badho
        current = next;       // current aage badho
    }
    head = prev;
    return head;
}

// Recursive Approach - O(n) time, O(n) space
public Node reverseRecursive(Node node) {
    if (node == null || node.next == null) {
        return node;
    }

    Node newHead = reverseRecursive(node.next);
    node.next.next = node;
    node.next = null;

    return newHead;
}

// Cycle hai ya nahi — O(n) time, O(1) space!
public boolean hasCycle() {
    if (head == null) return false;

    Node slow = head;  // Kachhua: 1 step
    Node fast = head;  // Khargosh: 2 steps

    while (fast != null && fast.next != null) {
        slow = slow.next;       // 1 step
        fast = fast.next.next;  // 2 steps

        if (slow == fast) {
            return true;  // Dono mile! Cycle hai.
        }
    }
    return false;  // Fast end pe pahuncha → cycle nahi hai
}

// Cycle KAHAN start hota hai — clever part!
public Node detectCycleStart() {
    Node slow = head, fast = head;

    // Phase 1: Meeting point dhundho
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) break;
    }

    if (fast == null || fast.next == null) return null;

    // Phase 2: Slow ko head pe reset karo, dono same speed se chalao
    slow = head;
    while (slow != fast) {
        slow = slow.next;
        fast = fast.next;  // Dono 1 step chalein
    }
    return slow;  // Yahan cycle start hota hai!
}

// Middle dhundho (Slow-Fast pointer)
public ListNode findMiddle(ListNode head) {
    ListNode slow = head, fast = head;
    while (fast != null && fast.next != null) {
        slow = slow.next;       // 1 step
        fast = fast.next.next;  // 2 steps
    }
    return slow;  // slow middle pe hai!
}
// [1,2,3,4,5] => slow=3 (middle)
// [1,2,3,4]   => slow=2 (pehla middle, even ke liye)

// Do sorted lists merge karo
public ListNode mergeSorted(ListNode l1, ListNode l2) {
    if (l1 == null) return l2;
    if (l2 == null) return l1;

    if (l1.val <= l2.val) {
        l1.next = mergeSorted(l1.next, l2);
        return l1;
    } else {
        l2.next = mergeSorted(l2, l1.next);
        return l2;
    }
}
// [1,3,5] + [2,4,6] => [1,2,3,4,5,6]

// Iterative merge (zyada efficient for large lists)
public ListNode mergeSortedIterative(ListNode l1, ListNode l2) {
    ListNode dummy = new ListNode(0);
    ListNode curr = dummy;
    while (l1 != null && l2 != null) {
        if (l1.val <= l2.val) { curr.next = l1; l1 = l1.next; }
        else { curr.next = l2; l2 = l2.next; }
        curr = curr.next;
    }
    curr.next = (l1 != null) ? l1 : l2;
    return dummy.next;
}

