// Balanced Parentheses - O(n)
public boolean isBalanced(String s) {
    Stack<Character> stack = new Stack<>();

    for (char c : s.toCharArray()) {
        if (c == '(' || c == '{' || c == '[') {
            stack.push(c);  // Opening bracket → stack mein daalo
        } else if (c == ')' || c == '}' || c == ']') {
            if (stack.isEmpty()) return false;  // Matching opening nahi hai

            char top = stack.pop();
            if ((c == ')' && top != '(') ||
                (c == '}' && top != '{') ||
                (c == ']' && top != '[')) {
                return false;  // Wrong match!
            }
        }
    }
    return stack.isEmpty();  // Sab match ho gaye toh khaali hona chahiye
}

// Right side ka Next Greater Element - O(n)
public int[] nextGreaterElement(int[] arr) {
    int n = arr.length;
    int[] result = new int[n];
    Stack<Integer> stack = new Stack<>();

    for (int i = n - 1; i >= 0; i--) {
        // Chhote ya equal hatao — kaam ke nahi
        while (!stack.isEmpty() && stack.peek() <= arr[i]) {
            stack.pop();
        }
        result[i] = stack.isEmpty() ? -1 : stack.peek();
        stack.push(arr[i]);
    }
    return result;
}

// Min Stack — O(1) mein minimum
class MinStack {
    private Stack<Integer> stack = new Stack<>();
    private Stack<Integer> minStack = new Stack<>();

    void push(int val) {
        stack.push(val);
        // Agar minStack empty ya naya val minimum hai
        if (minStack.isEmpty() || val <= minStack.peek()) {
            minStack.push(val);
        }
    }

    void pop() {
        if (stack.pop().equals(minStack.peek())) {
            minStack.pop();  // Minimum hi pop hua
        }
    }

    int getMin() { return minStack.peek(); } // O(1)!
}

// Postfix expression evaluate karo (3 4 + 2 *) => 14
public int evalPostfix(String[] tokens) {
    Stack<Integer> stack = new Stack<>();

    for (String token : tokens) {
        if (token.matches("-?\\d+")) {
            stack.push(Integer.parseInt(token));
        } else {
            int b = stack.pop(), a = stack.pop();
            switch (token) {
                case "+" -> stack.push(a + b);
                case "-" -> stack.push(a - b);
                case "*" -> stack.push(a * b);
                case "/" -> stack.push(a / b);
            }
        }
    }
    return stack.pop();
}

// Trapping Rainwater — O(n) stack solution
public int trap(int[] height) {
    Stack<Integer> stack = new Stack<>(); // indices store karo
    int water = 0;

    for (int i = 0; i < height.length; i++) {
        while (!stack.isEmpty() && height[i] > height[stack.peek()]) {
            int mid = stack.pop();
            if (!stack.isEmpty()) {
                int h = Math.min(height[stack.peek()], height[i]) - height[mid];
                int w = i - stack.peek() - 1;
                water += h * w;
            }
        }
        stack.push(i);
    }
    return water;
}
