// Basic Deque operations
Deque<Integer> dq = new ArrayDeque<>();
dq.addFirst(1);   // Front mein add: [1]
dq.addLast(2);    // Back mein add: [1,2]
dq.addFirst(0);   // Front mein add: [0,1,2]

int front = dq.peekFirst(); // 0 (front dekho)
int back  = dq.peekLast();  // 2 (back dekho)
dq.removeFirst();           // 0 nikalo
dq.removeLast();            // 2 nikalo

// Sliding Window Maximum — O(n)
// [1,3,-1,-3,5,3,6,7] window=3 => [3,3,5,5,6,7]
public int[] maxSlidingWindow(int[] nums, int k) {
    Deque<Integer> dq = new ArrayDeque<>();  // indices store karo
    int[] result = new int[nums.length - k + 1];

    for (int i = 0; i < nums.length; i++) {
        // Window se bahar nikle elements hata do
        if (!dq.isEmpty() && dq.peekFirst() < i - k + 1) {
            dq.pollFirst();
        }
        // Chote elements peeche se hata do
        while (!dq.isEmpty() && nums[dq.peekLast()] < nums[i]) {
            dq.pollLast();
        }
        dq.addLast(i);
        if (i >= k - 1) result[i - k + 1] = nums[dq.peekFirst()];
    }
    return result;
}

