// Bubble Sort - O(n²) time, O(1) space
// Socho: bade bubbles upar tairte hain
public void bubbleSort(int[] arr) {
    int n = arr.length;
    for (int i = 0; i < n - 1; i++) {
        boolean swapped = false;
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
                swapped = true;
            }
        }
        if (!swapped) break;  // Pehle se sorted hai!
    }
}

// Insertion Sort - O(n²) time, O(1) space
// Socho: taash ke patte sort karna
public void insertionSort(int[] arr) {
    int n = arr.length;
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;

        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];  // Shift karo
            j--;
        }
        arr[j + 1] = key;  // Sahi jagah rakh do
    }
}

// Merge Sort - O(n log n) time, O(n) space
// Socho: todko, sort karo, jodo
public void mergeSort(int[] arr, int left, int right) {
    if (left < right) {
        int mid = left + (right - left) / 2;
        mergeSort(arr, left, mid);        // Left half sort
        mergeSort(arr, mid + 1, right);   // Right half sort
        merge(arr, left, mid, right);     // Dono ko merge
    }
}

// Quick Sort - O(n log n) average, O(n²) worst
// Socho: pivot choose karo, chhote left, bade right
public void quickSort(int[] arr, int low, int high) {
    if (low < high) {
        int pi = partition(arr, low, high);
        quickSort(arr, low, pi - 1);
        quickSort(arr, pi + 1, high);
    }
}

private int partition(int[] arr, int low, int high) {
    int pivot = arr[high];
    int i = low - 1;

    for (int j = low; j < high; j++) {
        if (arr[j] < pivot) {
            i++;
            int temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
    }

    int temp = arr[i + 1];
    arr[i + 1] = arr[high];
    arr[high] = temp;
    return i + 1;
}

// Heap Sort
public void heapSort(int[] arr) {
    int n = arr.length;

    // Max heap banao
    for (int i = n/2 - 1; i >= 0; i--) {
        heapify(arr, n, i);
    }

    // Ek ek element Extract karo
    for (int i = n - 1; i > 0; i--) {
        int temp = arr[0]; arr[0] = arr[i]; arr[i] = temp;  // Swap
        heapify(arr, i, 0);  // Heap fix karo
    }
}

void heapify(int[] arr, int n, int i) {
    int largest = i;
    int left = 2*i + 1, right = 2*i + 2;
    if (left < n && arr[left] > arr[largest]) largest = left;
    if (right < n && arr[right] > arr[largest]) largest = right;
    if (largest != i) {
        int temp = arr[i]; arr[i] = arr[largest]; arr[largest] = temp;
        heapify(arr, n, largest);
    }
}

// Counting Sort
public void countingSort(int[] arr, int max) {
    int[] count = new int[max + 1];
    for (int x : arr) count[x]++;           // Count karo
    for (int i = 1; i <= max; i++) count[i] += count[i-1]; // Prefix sum

    int[] output = new int[arr.length];
    for (int i = arr.length - 1; i >= 0; i--) {
        output[--count[arr[i]]] = arr[i];
    }
    System.arraycopy(output, 0, arr, 0, arr.length);
}
