}

// Dijkstra's Algorithm - O((V + E) log V)
public int[] dijkstraWeighted(int start, List<List<int[]>> adjList) {
    int n = adjList.size();
    int[] dist = new int[n];
    Arrays.fill(dist, Integer.MAX_VALUE);
    dist[start] = 0;

    // Min-heap: {node, distance}
    PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[1] - b[1]);
    pq.offer(new int[]{start, 0});

    while (!pq.isEmpty()) {
        int[] current = pq.poll();
        int u = current[0];
        int d = current[1];

        if (d > dist[u]) continue;  // Purana distance, skip

        for (int[] edge : adjList.get(u)) {
            int v = edge[0];
            int weight = edge[1];

            if (dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.offer(new int[]{v, dist[v]});
            }
        }
    }
    return dist;
}

// Directed Graph mein Cycle Detection (DFS)
public boolean hasCycle(int n, int[][] edges) {
    List<List<Integer>> adj = new ArrayList<>();
    for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
    for (int[] e : edges) adj.get(e[0]).add(e[1]);

    boolean[] visited = new boolean[n];
    boolean[] inStack = new boolean[n];  // Current DFS path

    for (int i = 0; i < n; i++) {
        if (!visited[i] && dfs(i, adj, visited, inStack)) {
            return true;
        }
    }
    return false;
}

boolean dfs(int node, List<List<Integer>> adj,
            boolean[] visited, boolean[] inStack) {
    visited[node] = true;
    inStack[node] = true;

    for (int neighbor : adj.get(node)) {
        if (!visited[neighbor]) {
            if (dfs(neighbor, adj, visited, inStack)) return true;
        } else if (inStack[neighbor]) {
            return true;  // Back edge mila — cycle hai!
        }
    }
    inStack[node] = false;  // DFS path se nikala
    return false;
}

