// Method 2: Kahn's Algorithm (BFS based) — zyada intuitive
public int[] topSortBFS(int n, int[][] edges) {
    int[] inDegree = new int[n];
    List<List<Integer>> adj = new ArrayList<>();
    for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
    for (int[] e : edges) { adj.get(e[0]).add(e[1]); inDegree[e[1]]++; }

    Queue<Integer> queue = new LinkedList<>();
    for (int i = 0; i < n; i++) if (inDegree[i] == 0) queue.offer(i);

    int[] result = new int[n];
    int idx = 0;
    while (!queue.isEmpty()) {
        int node = queue.poll();
        result[idx++] = node;
        for (int nbr : adj.get(node)) {
            if (--inDegree[nbr] == 0) queue.offer(nbr);
        }
    }
    return idx == n ? result : new int[]{};  // Cycle hai agar idx != n
}

