// Two Sum - O(n)
public int[] twoSum(int[] nums, int target) {
    Map<Integer, Integer> map = new HashMap<>();

    for (int i = 0; i < nums.length; i++) {
        int complement = target - nums[i];
        if (map.containsKey(complement)) {
            return new int[]{map.get(complement), i};
        }
        map.put(nums[i], i);
    }
    return new int[]{-1, -1};
}

// Longest Consecutive Sequence - O(n)
public int longestConsecutive(int[] nums) {
    Set<Integer> set = new HashSet<>();
    for (int num : nums) set.add(num);

    int maxLen = 0;

    for (int num : set) {
        // Sirf tab start karo jab ye sequence ki shuruat ho
        if (!set.contains(num - 1)) {
            int currentNum = num;
            int currentLen = 1;

            while (set.contains(currentNum + 1)) {
                currentNum++;
                currentLen++;
            }
            maxLen = Math.max(maxLen, currentLen);
        }
    }
    return maxLen;
}

// Permutations - O(n!)
public List<List<Integer>> permute(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    backtrack(nums, new ArrayList<>(), result, new boolean[nums.length]);
    return result;
}

private void backtrack(int[] nums, List<Integer> current, 
                      List<List<Integer>> result, boolean[] used) {
    if (current.size() == nums.length) {
        result.add(new ArrayList<>(current));  // Ek arrangement mil gaya!
        return;
    }

    for (int i = 0; i < nums.length; i++) {
        if (used[i]) continue;  // Ye pehle se use ho chuka

        current.add(nums[i]);   // Try karo
        used[i] = true;

        backtrack(nums, current, result, used);  // Aage badho

        current.remove(current.size() - 1);  // Undo karo (backtrack)
        used[i] = false;
    }
}

// Subsets - O(2^n)
public List<List<Integer>> subsets(int[] nums) {
    List<List<Integer>> result = new ArrayList<>();
    backtrack(nums, 0, new ArrayList<>(), result);
    return result;
}

private void backtrack(int[] nums, int start, 
                      List<Integer> current, List<List<Integer>> result) {
    result.add(new ArrayList<>(current));  // Har subset add karo

    for (int i = start; i < nums.length; i++) {
        current.add(nums[i]);
        backtrack(nums, i + 1, current, result);
        current.remove(current.size() - 1);  // Backtrack
    }
}

// N-Queens
public List<List<String>> solveNQueens(int n) {
    List<List<String>> result = new ArrayList<>();
    char[][] board = new char[n][n];
    for (char[] row : board) Arrays.fill(row, '.');
    solve(board, 0, result);
    return result;
}

void solve(char[][] board, int row, List<List<String>> result) {
    if (row == board.length) {
        result.add(boardToList(board));  // Solution mili!
        return;
    }
    for (int col = 0; col < board.length; col++) {
        if (isSafe(board, row, col)) {
            board[row][col] = 'Q';         // Place karo
            solve(board, row + 1, result); // Aage badho
            board[row][col] = '.';         // Backtrack karo
        }
    }
}

boolean isSafe(char[][] board, int row, int col) {
    // Upar same column check karo
    for (int i = 0; i < row; i++)
        if (board[i][col] == 'Q') return false;
    // Upar-left diagonal
    for (int i = row-1, j = col-1; i >= 0 && j >= 0; i--, j--)
        if (board[i][j] == 'Q') return false;
    // Upar-right diagonal
    for (int i = row-1, j = col+1; i >= 0 && j < board.length; i--, j++)
        if (board[i][j] == 'Q') return false;
    return true;
}

// Sudoku — har empty cell pe 1-9 try karo
void solveSudoku(char[][] board) {
    for (int r = 0; r < 9; r++) {
        for (int c = 0; c < 9; c++) {
            if (board[r][c] == '.') {
                for (char num = '1'; num <= '9'; num++) {
                    if (isValid(board, r, c, num)) {
                        board[r][c] = num;
                        if (solveSudoku(board)) return; // Aggggge!
                        board[r][c] = '.';  // Backtrack
                    }
                }
                return;  // Koi number fit nahi hua
            }
        }
    }
}

// N-Queens
public List<List<String>> solveNQueens(int n) {
    List<List<String>> result = new ArrayList<>();
    char[][] board = new char[n][n];
    for (char[] row : board) Arrays.fill(row, '.');
    solve(board, 0, result);
    return result;
}

void solve(char[][] board, int row, List<List<String>> result) {
    if (row == board.length) {
        // Board ko list of strings mein convert karo
        List<String> solution = new ArrayList<>();
        for (char[] r : board) solution.add(new String(r));
        result.add(solution);
        return;
    }
    for (int col = 0; col < board.length; col++) {
        if (isSafe(board, row, col)) {
            board[row][col] = 'Q';         // Place karo
            solve(board, row + 1, result); // Aage badho
            board[row][col] = '.';         // Backtrack karo
        }
    }
}

boolean isSafe(char[][] board, int row, int col) {
    // Upar same column check karo
    for (int i = 0; i < row; i++)
        if (board[i][col] == 'Q') return false;
    // Upar-left diagonal
    for (int i = row-1, j = col-1; i >= 0 && j >= 0; i--, j--)
        if (board[i][j] == 'Q') return false;
    // Upar-right diagonal
    for (int i = row-1, j = col+1; i >= 0 && j < board.length; i--, j++)
        if (board[i][j] == 'Q') return false;
    return true;
}

// Sudoku: har empty cell pe 1-9 try karo
boolean solveSudoku(char[][] board) {
    for (int r = 0; r < 9; r++) {
        for (int c = 0; c < 9; c++) {
            if (board[r][c] == '.') {
                for (char num = '1'; num <= '9'; num++) {
                    if (isValidSudoku(board, r, c, num)) {
                        board[r][c] = num;
                        if (solveSudoku(board)) return true;
                        board[r][c] = '.';  // Backtrack
                    }
                }
                return false;  // Koi number fit nahi hua
            }
        }
    }
    return true;
}

// Activity Selection: Maximum activities karo
// (start, end) pairs — minimum overlaps
public int activitySelection(int[] start, int[] end) {
    int n = start.length;
    Integer[] idx = new Integer[n];
    for (int i = 0; i < n; i++) idx[i] = i;

    // End time ke hisaab se sort karo (greedy choice!)
    Arrays.sort(idx, (a, b) -> end[a] - end[b]);

    int count = 1;
    int lastEnd = end[idx[0]];  // Pehli activity

    for (int i = 1; i < n; i++) {
        if (start[idx[i]] >= lastEnd) {
            count++;
            lastEnd = end[idx[i]];
        }
    }
    return count;
}

// Merge Intervals
public int[][] mergeIntervals(int[][] intervals) {
    Arrays.sort(intervals, (a, b) -> a[0] - b[0]);
    List<int[]> merged = new ArrayList<>();

    for (int[] interval : intervals) {
        if (merged.isEmpty() || merged.get(merged.size()-1)[1] < interval[0]) {
            merged.add(interval);  // Overlap nahi — add karo
        } else {
            // Overlap — extend karo
            merged.get(merged.size()-1)[1] =
                Math.max(merged.get(merged.size()-1)[1], interval[1]);
        }
    }
    return merged.toArray(new int[0][]);
}
// [[1,3],[2,6],[8,10],[15,18]] => [[1,6],[8,10],[15,18]]

// Jump Game I: Kya last tak pahunch sakte ho?
// nums[i] = maximum jump length from i
public boolean canJump(int[] nums) {
    int maxReach = 0;
    for (int i = 0; i < nums.length; i++) {
        if (i > maxReach) return false;  // Yahan pahunch hi nahi sakte!
        maxReach = Math.max(maxReach, i + nums[i]);
    }
    return true;
}
// [2,3,1,1,4] => true
// [3,2,1,0,4] => false (index 3 pe stuck)

// Jump Game II: Minimum jumps
public int minJumps(int[] nums) {
    int jumps = 0, currEnd = 0, farthest = 0;
    for (int i = 0; i < nums.length - 1; i++) {
        farthest = Math.max(farthest, i + nums[i]);
        if (i == currEnd) {  // Current jump khatam hua
            jumps++;
            currEnd = farthest;
        }
    }
    return jumps;
}
// [2,3,1,1,4] => 2 jumps (index 0->1->4)

// Gas Station: Circular route possible?
public int canCompleteCircuit(int[] gas, int[] cost) {
    int total = 0, tank = 0, start = 0;
    for (int i = 0; i < gas.length; i++) {
        tank += gas[i] - cost[i];
        total += gas[i] - cost[i];
        if (tank < 0) { start = i + 1; tank = 0; }
    }
    return total >= 0 ? start : -1;
}

