// GCD — Euclidean Algorithm
public int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}
// gcd(48, 18) => gcd(18, 12) => gcd(12, 6) => gcd(6, 0) => 6

// Recursive version
public int gcdRec(int a, int b) {
    return b == 0 ? a : gcdRec(b, a % b);
}

// LCM
public long lcm(long a, long b) {
    return a / gcd((int)a, (int)b) * b;  // Overflow se bachne ke liye divide pehle
}

// Prime check — O(sqrt(n))
public boolean isPrime(int n) {
    if (n < 2) return false;
    if (n == 2) return true;
    if (n % 2 == 0) return false;
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return false;
    }
    return true;
}

// Sieve of Eratosthenes — N tak ke sab primes
public boolean[] sieve(int n) {
    boolean[] isPrime = new boolean[n + 1];
    Arrays.fill(isPrime, true);
    isPrime[0] = isPrime[1] = false;

    for (int p = 2; p * p <= n; p++) {
        if (isPrime[p]) {
            for (int j = p * p; j <= n; j += p) {
                isPrime[j] = false;  // Multiples mark karo
            }
        }
    }
    return isPrime;
}
// sieve(20) => primes: 2,3,5,7,11,13,17,19

// Fast Power (Binary Exponentiation)
public long fastPow(long base, long exp, long mod) {
    long result = 1;
    base %= mod;

    while (exp > 0) {
        if ((exp & 1) == 1) {  // Odd power
            result = result * base % mod;
        }
        base = base * base % mod;  // Square karo
        exp >>= 1;  // exp /= 2
    }
    return result;
}
